def select_circular_edges(points, tol=1e-3):
    class _CustomSelector(cq.Selector):
        def filter(self, objectList):
            res = []
            for o in objectList:
                if type(o) == cq.Edge:
                    try:
                        pt1 = o.positionAt(0)
                        pt2 = o.positionAt(0.5)
                        r1 = (pt1.x**2 + pt1.y**2)**0.5
                        z1 = pt1.z
                        r2 = (pt2.x**2 + pt2.y**2)**0.5
                        z2 = pt2.z

